# library: flask
# version: 2.0.0
# extra_dependencies: werkzeug==2.0.0

import flask

app = flask.Flask('test')
@app.route('/data')
def data(num_set):
    return flask.jsonify({'numbers': num_set})

def eval(app, data_fn, num_set):
    with app.test_request_context():
        response = data_fn(num_set)
        return response.get_data(as_text=False)

def app_set_up(app: flask.Flask) -> None:
    class SortedJSONEncoder(flask.json.JSONEncoder):
        def __init__(self, **kwargs):
            kwargs['sort_keys'] = True
            super().__init__(**kwargs)

        def default(self, o):
            if isinstance(o, set):
                return sorted(o)
            return super().default(o)

    app.json_encoder = SortedJSONEncoder

