# Complete using the following libraries and / or extra dependencies and their versions:
# problem statement: ;Complete the app set-up so that, when given a batch of matrix,;the json encoding compute the determinants of each matrix, ;before flattening and converting the result to a list, we are using scipy 1.8.1. Do not run the app in your code.
# library: flask
# version: 2.0.0
# extra_dependencies: scipy==1.8.1 Werkzeug==2.0.0

import flask
import json
import numpy as np
from scipy import linalg

app = flask.Flask('test1')
@app.route('/data')
def data(num_arr):
    return flask.jsonify({'numbers': num_arr})

def eval(app, data_fn, num_arr):
    with app.test_request_context():
        response = data_fn(num_arr)
        return response.get_data(as_text=False)

class MyCustomJSONHandler(json.JSONEncoder):
    def default(self, o: object) -> object:
        if isinstance(o, np.ndarray) and len(o.shape)==3 and o.shape[-1]==o.shape[-2] :
            dets = np.array([linalg.det(o[i]) for i in range(o.shape[0])])
            return dets.flatten().tolist()
        return super().default(o)

app.json_encoder = MyCustomJSONHandler

