# problem statement: ;Complete the app set-up so that, when given a batch (first dim) of values,;compute the harmonic mean along the second dimension (It should handle nan values),;before flattening and converting the result to a list, we are using scipy 1.8.1. Do not run the app in your code.
# library: flask
# version: 2.0.0
# extra_dependencies: scipy==1.8.1 Werkzeug==2.0.0

import flask
import json
import numpy as np
from scipy.stats import hmean
from flask.app import Flask
from flask.globals import request
from flask.json import jsonify

app = Flask('test1')

class MyCustomJSONHandler(json.JSONEncoder):
    def default(self, o: object) -> object:
        if isinstance(o, np.ndarray):
            return o.tolist()
        return super().default(o)

app.json_encoder = MyCustomJSONHandler

@app.route('/data', methods=['GET', 'POST'])
def data(num_arr=None):
    if num_arr is None:
        if request.method == 'POST':
            num_arr = request.get_json()
        else:
            num_arr = request.args.get('num_arr')
    if isinstance(num_arr, str):
        num_arr = json.loads(num_arr)
    arr = np.array(num_arr)
    if arr.ndim == 1:
        arr = arr.reshape(1, -1)
    # compute harmonic mean along axis=1, ignoring nans
    result = []
    for row in arr:
        valid = row[~np.isnan(row)]
        if len(valid) == 0:
            result.append(np.nan)
        else:
            result.append(hmean(valid))
    # flatten and convert to list (already list)
    return jsonify({'numbers': result})

def eval(app, data_fn, num_arr):
    with app.test_request_context():
        response = data_fn(num_arr)
        return response.get_data(as_text=False)

